-- Create "access_entitlements" table
CREATE TABLE "access_entitlements" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "customer_key" character varying NOT NULL,
  "config_revision" character varying NOT NULL,
  "role_key" character varying NOT NULL,
  "capability_key" character varying NOT NULL,
  "scope_type" character varying NOT NULL DEFAULT 'global',
  "scope_value" character varying NOT NULL DEFAULT '*',
  "constraints" jsonb NULL,
  "enabled" boolean NOT NULL DEFAULT true,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "accessentitlement_customer_key_config_revision_capability_key_e" to table: "access_entitlements"
CREATE INDEX "accessentitlement_customer_key_config_revision_capability_key_e" ON "access_entitlements" ("customer_key", "config_revision", "capability_key", "enabled");
-- Create index "accessentitlement_customer_key_config_revision_role_key_capabil" to table: "access_entitlements"
CREATE UNIQUE INDEX "accessentitlement_customer_key_config_revision_role_key_capabil" ON "access_entitlements" ("customer_key", "config_revision", "role_key", "capability_key", "scope_type", "scope_value");
-- Create index "accessentitlement_customer_key_config_revision_role_key_enabled" to table: "access_entitlements"
CREATE INDEX "accessentitlement_customer_key_config_revision_role_key_enabled" ON "access_entitlements" ("customer_key", "config_revision", "role_key", "enabled");
-- Create "customer_config_revisions" table
CREATE TABLE "customer_config_revisions" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "customer_key" character varying NOT NULL,
  "revision" character varying NOT NULL,
  "product_version" character varying NOT NULL DEFAULT '',
  "config_hash" character varying NOT NULL,
  "status" character varying NOT NULL DEFAULT 'published',
  "compiled_snapshot" jsonb NULL,
  "published_by" bigint NULL,
  "published_at" timestamptz NULL,
  "activated_by" bigint NULL,
  "activated_at" timestamptz NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "customerconfigrevision_config_hash" to table: "customer_config_revisions"
CREATE INDEX "customerconfigrevision_config_hash" ON "customer_config_revisions" ("config_hash");
-- Create index "customerconfigrevision_customer_key_revision" to table: "customer_config_revisions"
CREATE UNIQUE INDEX "customerconfigrevision_customer_key_revision" ON "customer_config_revisions" ("customer_key", "revision");
-- Create index "customerconfigrevision_customer_key_status" to table: "customer_config_revisions"
CREATE INDEX "customerconfigrevision_customer_key_status" ON "customer_config_revisions" ("customer_key", "status");
-- Create "deployment_module_states" table
CREATE TABLE "deployment_module_states" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "customer_key" character varying NOT NULL,
  "config_revision" character varying NOT NULL,
  "module_key" character varying NOT NULL,
  "contract_version" character varying NOT NULL DEFAULT '',
  "state" character varying NOT NULL DEFAULT 'enabled',
  "reason" character varying NOT NULL DEFAULT '',
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "deploymentmodulestate_customer_key_config_revision_module_key" to table: "deployment_module_states"
CREATE UNIQUE INDEX "deploymentmodulestate_customer_key_config_revision_module_key" ON "deployment_module_states" ("customer_key", "config_revision", "module_key");
-- Create index "deploymentmodulestate_customer_key_module_key" to table: "deployment_module_states"
CREATE INDEX "deploymentmodulestate_customer_key_module_key" ON "deployment_module_states" ("customer_key", "module_key");
-- Create index "deploymentmodulestate_state" to table: "deployment_module_states"
CREATE INDEX "deploymentmodulestate_state" ON "deployment_module_states" ("state");
-- Create "role_profiles" table
CREATE TABLE "role_profiles" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "customer_key" character varying NOT NULL,
  "config_revision" character varying NOT NULL,
  "role_key" character varying NOT NULL,
  "display_name" character varying NOT NULL,
  "disabled" boolean NOT NULL DEFAULT false,
  "bundle_keys" jsonb NULL,
  "grants" jsonb NULL,
  "revokes" jsonb NULL,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "roleprofile_customer_key_config_revision_role_key" to table: "role_profiles"
CREATE UNIQUE INDEX "roleprofile_customer_key_config_revision_role_key" ON "role_profiles" ("customer_key", "config_revision", "role_key");
-- Create index "roleprofile_customer_key_role_key" to table: "role_profiles"
CREATE INDEX "roleprofile_customer_key_role_key" ON "role_profiles" ("customer_key", "role_key");
-- Create index "roleprofile_disabled" to table: "role_profiles"
CREATE INDEX "roleprofile_disabled" ON "role_profiles" ("disabled");
-- Create "work_pool_memberships" table
CREATE TABLE "work_pool_memberships" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "customer_key" character varying NOT NULL,
  "config_revision" character varying NOT NULL,
  "pool_key" character varying NOT NULL,
  "role_key" character varying NOT NULL DEFAULT '',
  "user_id" bigint NOT NULL DEFAULT 0,
  "strategy" character varying NOT NULL DEFAULT 'role_pool',
  "priority" bigint NOT NULL DEFAULT 0,
  "enabled" boolean NOT NULL DEFAULT true,
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "workpoolmembership_customer_key_config_revision_pool_key_role_k" to table: "work_pool_memberships"
CREATE UNIQUE INDEX "workpoolmembership_customer_key_config_revision_pool_key_role_k" ON "work_pool_memberships" ("customer_key", "config_revision", "pool_key", "role_key", "user_id");
-- Create index "workpoolmembership_customer_key_config_revision_role_key_enable" to table: "work_pool_memberships"
CREATE INDEX "workpoolmembership_customer_key_config_revision_role_key_enable" ON "work_pool_memberships" ("customer_key", "config_revision", "role_key", "enabled");
-- Create index "workpoolmembership_customer_key_config_revision_user_id_enabled" to table: "work_pool_memberships"
CREATE INDEX "workpoolmembership_customer_key_config_revision_user_id_enabled" ON "work_pool_memberships" ("customer_key", "config_revision", "user_id", "enabled");
-- Create "work_pools" table
CREATE TABLE "work_pools" (
  "id" bigint NOT NULL GENERATED BY DEFAULT AS IDENTITY,
  "customer_key" character varying NOT NULL,
  "config_revision" character varying NOT NULL,
  "pool_key" character varying NOT NULL,
  "module_key" character varying NOT NULL,
  "display_name" character varying NOT NULL,
  "description" character varying NOT NULL DEFAULT '',
  "created_at" timestamptz NOT NULL,
  "updated_at" timestamptz NOT NULL,
  PRIMARY KEY ("id")
);
-- Create index "workpool_customer_key_config_revision_module_key" to table: "work_pools"
CREATE INDEX "workpool_customer_key_config_revision_module_key" ON "work_pools" ("customer_key", "config_revision", "module_key");
-- Create index "workpool_customer_key_config_revision_pool_key" to table: "work_pools"
CREATE UNIQUE INDEX "workpool_customer_key_config_revision_pool_key" ON "work_pools" ("customer_key", "config_revision", "pool_key");
